-- Phase 2: Diagnostics Service Independent Database Schema\n-- Database: postgres-diagnostics:5437\n-- Schema: aivery_diagnostics\n-- User: diagnostics_user\n\n-- ============================================================================\n-- DIAGNOSTICS TABLE\n-- ============================================================================\nCREATE TABLE IF NOT EXISTS diagnostics (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    user_id UUID NOT NULL,\n    status VARCHAR(20),  -- 'pending', 'processing', 'completed', 'failed'\n    started_at TIMESTAMP,\n    completed_at TIMESTAMP,\n    result_summary TEXT,\n    readiness_score INT,\n    created_at TIMESTAMP DEFAULT NOW()\n);\n\n-- ============================================================================\n-- SYMPTOMS TABLE\n-- ============================================================================\nCREATE TABLE IF NOT EXISTS symptoms (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    diagnostic_id UUID NOT NULL REFERENCES diagnostics(id) ON DELETE CASCADE,\n    symptom TEXT,\n    severity INT,\n    created_at TIMESTAMP DEFAULT NOW()\n);\n\n-- ============================================================================\n-- ASSESSMENTS TABLE\n-- ============================================================================\nCREATE TABLE IF NOT EXISTS assessments (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    diagnostic_id UUID NOT NULL REFERENCES diagnostics(id) ON DELETE CASCADE,\n    assessment_type VARCHAR(50),\n    score DECIMAL(5, 2),\n    details TEXT,\n    created_at TIMESTAMP DEFAULT NOW()\n);\n\n-- ============================================================================\n-- RECOMMENDATIONS TABLE\n-- ============================================================================\nCREATE TABLE IF NOT EXISTS recommendations (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    diagnostic_id UUID NOT NULL REFERENCES diagnostics(id) ON DELETE CASCADE,\n    recommendation TEXT,\n    priority VARCHAR(20),  -- 'high', 'medium', 'low'\n    created_at TIMESTAMP DEFAULT NOW()\n);\n\n-- ============================================================================\n-- ML MODELS TABLE\n-- ============================================================================\nCREATE TABLE IF NOT EXISTS ml_models (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    name VARCHAR(100),\n    version VARCHAR(20),\n    accuracy DECIMAL(5, 4),\n    is_active BOOLEAN DEFAULT true,\n    created_at TIMESTAMP DEFAULT NOW()\n);\n\n-- ============================================================================\n-- INDEXES FOR PERFORMANCE\n-- ============================================================================\nCREATE INDEX idx_diagnostics_user_id ON diagnostics(user_id);\nCREATE INDEX idx_diagnostics_status ON diagnostics(status);\nCREATE INDEX idx_diagnostics_created_at ON diagnostics(created_at);\n\nCREATE INDEX idx_symptoms_diagnostic_id ON symptoms(diagnostic_id);\nCREATE INDEX idx_assessments_diagnostic_id ON assessments(diagnostic_id);\nCREATE INDEX idx_recommendations_diagnostic_id ON recommendations(diagnostic_id);\nCREATE INDEX idx_ml_models_name ON ml_models(name);\nCREATE INDEX idx_ml_models_active ON ml_models(is_active);\n\n-- ============================================================================\n-- GRANTS (for diagnostics_user)\n-- ============================================================================\nGRANT USAGE ON SCHEMA public TO diagnostics_user;\nGRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO diagnostics_user;\nGRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO diagnostics_user;\n\n-- ============================================================================\n-- MIGRATION INFO\n-- ============================================================================\n-- Created: 2026-06-05\n-- Version: 1.0\n-- Purpose: Phase 2 Diagnostics Service Independent Database Schema\n-- Status: Production Ready\n"